#!/usr/bin/env bash
#
# demo-autofork.sh — a runnable, end-to-end demonstration that the swarm
# REGULATES ITSELF on a live partyline, within the FRF guardrails, with every
# autonomic move audited.
#
# The autonomic loop (`monster-swarm auto`) reads the UDP partyline — the
# collective consciousness the swarm broadcasts to itself — and, per the
# AntColony FRF budget, acts on its own:
#
#   BUD ON HOT  — when the collective is loud (consciousness >= --bud-at), the
#                 loop BUDS a scout to absorb the load.
#   CEILING     — it never buds past the DECAGON ceiling (DECAGON = 10): the FRF
#                 manifold bounds the autonomic population. Hot or not, the loop
#                 cannot run the fleet away.
#   REAP ON CALM— when the collective falls quiet (consciousness <= --reap-below),
#                 the loop REAPS the oldest idle scout, venting capacity it no
#                 longer needs.
#   FLOOR       — it never reaps below the two-queen floor (--min-live): at least
#                 one breeder always survives, so a single queen loss is
#                 recoverable (budding_survives_one_queen_loss).
#   AUDITED     — every autonomic Spawn/Reap is tagged actor "auto" and appended
#                 to the tamper-evident hash chain. `audit --verify` recomputes
#                 the chain: the swarm acting on its own is on the record.
#
# The DRIVER that makes the partyline hot/calm is `monster-swarm broadcast`
# (sibling-provided). It emits SwarmSignal(s) onto the UDP partyline so the
# `auto` loop has a live collective consciousness to read. If `broadcast` is not
# in the binary at run time, the SIGNAL-DRIVEN gates (G1/G2/G3) cannot fire on
# live data, so they SKIP cleanly with a note; the structural gates (queen seed,
# floor, audit/verify, stability weight) still run against the real binaries.
# The lead runs the full green pass after reconciliation.
#
# This script sets up an ISOLATED MONSTER_GUARD_HOME, mints a holder UCAN with a
# freshly-generated DID, seeds one QUEEN (a breeder, so the two-queen floor is
# satisfiable), then walks each gate printing the OBSERVED result with PASS /
# FAIL / SKIP banners. It changes nothing outside its temp home and reaps every
# proc it starts (the background broadcaster, the /bin/sleep nodes, the
# monster-guard supervisors) via the EXIT trap.
#
# Usage:  bash scripts/demo-autofork.sh
#
# No emojis. No git. No build. No third-party inference.

set -euo pipefail

# ---------------------------------------------------------------------------
# Locate the gnosis tree and resolve the release binaries.
# ---------------------------------------------------------------------------
script_dir="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
swarm_dir="$(cd "${script_dir}/.." && pwd)"          # .../gnosis/monster-swarm
gnosis_dir="$(cd "${swarm_dir}/.." && pwd)"          # .../gnosis

GUARD_BIN="${gnosis_dir}/monster-guard/target/release/monster-guard"
RESIDENT_BIN="${gnosis_dir}/monster-resident/target/release/monster-resident"
SWARM_BIN="${gnosis_dir}/monster-swarm/target/release/monster-swarm"

for pair in \
  "monster-guard:${GUARD_BIN}" \
  "monster-resident:${RESIDENT_BIN}" \
  "monster-swarm:${SWARM_BIN}"; do
  name="${pair%%:*}"; path="${pair#*:}"
  if [[ ! -x "${path}" ]]; then
    echo "error: ${name} release binary not found at:" >&2
    echo "       ${path}" >&2
    echo "       build it first: (cd ${gnosis_dir}/${name} && cargo build --release)" >&2
    exit 1
  fi
done

# ---------------------------------------------------------------------------
# Isolated, disposable state: temp MONSTER_GUARD_HOME + the guard binary +
# /bin as the node allowlist (so the demo can treat `sleep` as a node — the
# bud node the autonomic loop will spawn is /bin/sleep).
# ---------------------------------------------------------------------------
MONSTER_GUARD_HOME="$(mktemp -d "${TMPDIR:-/tmp}/monster-autofork-demo.XXXXXX")"
export MONSTER_GUARD_HOME
export MONSTER_GUARD_BIN="${GUARD_BIN}"
export MONSTER_SWARM_NODES="/bin"

# FRF guardrail constants the loop enforces (mirrored here for the banners).
DECAGON=10            # autonomic population ceiling
MIN_LIVE=1            # two-queen floor expressed as min live (>=1 breeder kept)

# Track the background broadcaster pid so cleanup can always reap it.
BROADCAST_PID=""

cleanup() {
  echo
  banner "CLEANUP"
  # Stop the background broadcaster first (it holds the partyline hot).
  if [[ -n "${BROADCAST_PID}" ]]; then
    kill "${BROADCAST_PID}" 2>/dev/null || true
    wait "${BROADCAST_PID}" 2>/dev/null || true
  fi
  # Kill any guard supervisors / sleep nodes this demo started.
  pkill -f "${GUARD_BIN}" 2>/dev/null || true
  pkill -f "/bin/sleep 3600" 2>/dev/null || true
  pkill -f "/bin/sleep 1" 2>/dev/null || true
  if [[ -n "${MONSTER_GUARD_HOME:-}" && -d "${MONSTER_GUARD_HOME}" ]]; then
    rm -rf "${MONSTER_GUARD_HOME}"
    echo "removed temp home: ${MONSTER_GUARD_HOME}"
  fi
  echo "done."
}
trap cleanup EXIT INT TERM

# ---------------------------------------------------------------------------
# Pretty output helpers.
# ---------------------------------------------------------------------------
banner() {
  echo
  echo "============================================================"
  echo "  $*"
  echo "============================================================"
}

# Extract a JSON string field with a portable sed.
json_field() {
  # $1 = field name, $2 = json text
  printf '%s' "$2" | sed -n "s/.*\"$1\"[[:space:]]*:[[:space:]]*\"\([^\"]*\)\".*/\1/p"
}

# Read .fleet.live out of `vibe --json` (stdout only). Echoes an integer or "".
fleet_live() {
  local v; v="$("${SWARM_BIN}" vibe --json 2>/dev/null || true)"
  printf '%s' "${v}" | tr -d '\n ' \
    | sed -n 's/.*"fleet":{[^}]*"live":\([0-9][0-9]*\).*/\1/p' | head -n 1
}

# Read .fleet.breeders out of `vibe --json` (stdout only).
fleet_breeders() {
  local v; v="$("${SWARM_BIN}" vibe --json 2>/dev/null || true)"
  printf '%s' "${v}" | tr -d '\n ' \
    | sed -n 's/.*"fleet":{[^}]*"breeders":\([0-9][0-9]*\).*/\1/p' | head -n 1
}

# Read .fleet.stabilityWeight out of `vibe --json` (stdout only).
fleet_stability() {
  local v; v="$("${SWARM_BIN}" vibe --json 2>/dev/null || true)"
  printf '%s' "${v}" | tr -d '\n ' \
    | sed -n 's/.*"stabilityWeight":\([0-9][0-9]*\).*/\1/p' | head -n 1
}

# Count audit entries whose actor is autonomic (the actor value STARTS WITH
# "auto" — the loop tags itself "auto:<did>") AND whose kind matches $1
# (e.g. spawn|reap). Reads `audit --json` stdout only. Echoes an integer.
auto_action_count() {
  local kind="$1" j
  j="$("${SWARM_BIN}" audit --json 2>/dev/null || true)"
  # Split the entries array into one object per line, keep the auto-actor kind
  # rows. The two greps are order-independent (actor/kind can appear in any order
  # within an object); the first keeps kind==$1 rows, the second keeps auto rows.
  printf '%s' "${j}" | tr -d '\n' \
    | sed 's/},[[:space:]]*{/}\n{/g' \
    | grep "\"kind\"[[:space:]]*:[[:space:]]*\"${kind}\"" \
    | grep -c "\"actor\"[[:space:]]*:[[:space:]]*\"auto" \
    || true
}

# Run one autonomic tick (single tick: `auto` with no --interval is one read +
# decide + act). The status line the loop prints (e.g. "auto [bud] ..." /
# "auto [hold] ...") goes to stderr; we capture it, surface it indented to the
# operator on STDERR (so it is visible but not part of this function's value),
# and echo ONLY the decision token (bud | reap | hold) on STDOUT so a caller can
# do `tok="$(auto_tick ...)"` and tally decisions. Never aborts under set -e.
auto_tick() {
  # $@ extra flags appended after the standard ones.
  local out tok
  out="$("${SWARM_BIN}" auto \
    --ucan "${UCAN}" \
    --node sleep \
    --min-live "${MIN_LIVE}" \
    --dwell-ms 150 \
    "$@" 2>&1 || true)"
  # Human-readable status to stderr (visible on the terminal, not captured).
  printf '%s\n' "${out}" | sed 's/^/      /' >&2
  # Decision token to stdout (the function's value). Match "[bud]"/"[reap]"/etc.
  tok="$(printf '%s' "${out}" | sed -n 's/.*\[\([a-z][a-z]*\)\].*/\1/p' | head -n 1)"
  printf '%s' "${tok:-hold}"
}

# ---------------------------------------------------------------------------
# Feature probe: is the `broadcast` driver in the binary yet? It is what makes
# the partyline hot/calm so the autonomic loop has a live collective
# consciousness to read. Capture COMBINED output (clap banners land on either
# stream) and never let a nonzero exit kill the demo under set -e.
# ---------------------------------------------------------------------------
BROADCAST_PRESENT=0
broadcast_probe="$("${SWARM_BIN}" broadcast --consciousness 0 --count 0 2>&1 || true)"
if ! printf '%s' "${broadcast_probe}" | grep -Eqi 'unknown subcommand|unexpected argument|unrecognized'; then
  BROADCAST_PRESENT=1
fi

# Start the background broadcaster that holds the partyline at consciousness $1
# for the duration of the signal-driven gates. Sets BROADCAST_PID. No-op (and
# leaves BROADCAST_PID empty) if broadcast is absent.
start_hot_broadcast() {
  local level="$1" secs="$2"
  [[ "${BROADCAST_PRESENT}" -eq 1 ]] || return 0
  "${SWARM_BIN}" broadcast \
    --consciousness "${level}" \
    --energy 5 \
    --id demo-driver \
    --hz 5 \
    --secs "${secs}" \
    >/dev/null 2>&1 &
  BROADCAST_PID="$!"
}

stop_broadcast() {
  if [[ -n "${BROADCAST_PID}" ]]; then
    kill "${BROADCAST_PID}" 2>/dev/null || true
    wait "${BROADCAST_PID}" 2>/dev/null || true
    BROADCAST_PID=""
  fi
}

# ===========================================================================
# SETUP — mint a holder UCAN (agent/*), seed one QUEEN (breeder).
# ===========================================================================
banner "SETUP — mint a holder UCAN (agent/*) and seed a QUEEN"
echo "MONSTER_GUARD_HOME = ${MONSTER_GUARD_HOME}"
echo "MONSTER_GUARD_BIN  = ${MONSTER_GUARD_BIN}"
echo "MONSTER_SWARM_NODES= ${MONSTER_SWARM_NODES} (bud node = /bin/sleep)"
echo "FRF guardrails     : DECAGON ceiling = ${DECAGON}, min-live floor = ${MIN_LIVE}"
if [[ "${BROADCAST_PRESENT}" -eq 1 ]]; then
  echo "broadcast driver   : present (live partyline; signal gates will fire)"
else
  echo "broadcast driver   : ABSENT (sibling-pending; signal gates G1/G2/G3 will SKIP)"
fi
echo

keygen_json="$("${RESIDENT_BIN}" keygen)"
FLEET_DID="$(json_field did "${keygen_json}")"
FLEET_SECRET="$(json_field secret "${keygen_json}")"
if [[ -z "${FLEET_DID}" || -z "${FLEET_SECRET}" ]]; then
  echo "error: could not parse DID/secret from keygen output: ${keygen_json}" >&2
  exit 1
fi
echo "minted holder DID: ${FLEET_DID}"

UCAN="$("${RESIDENT_BIN}" grant \
  --audience "${FLEET_DID}" \
  --with agent:fleet \
  --can 'agent/*')"
if [[ -z "${UCAN}" ]]; then
  echo "error: grant produced an empty UCAN token." >&2
  exit 1
fi
echo "minted holder UCAN: agent/* on agent:fleet (rooted at the resident)"

echo
echo "--- seed a QUEEN (a breeder, so the two-queen floor is satisfiable) -> expect 1 live"
if "${SWARM_BIN}" spawn \
      --ucan "${UCAN}" \
      --node sleep \
      --id queen-1 \
      --caste breeder \
      --caps net \
      --lease 3600 \
      --grant-ttl 3600 \
      -- 3600 >/dev/null 2>&1; then
  SEED_LIVE="$(fleet_live)"
  SEED_BREEDERS="$(fleet_breeders)"
  echo "    fleet now: live=${SEED_LIVE:-?} breeders=${SEED_BREEDERS:-?}"
  if [[ "${SEED_LIVE:-0}" -ge 1 && "${SEED_BREEDERS:-0}" -ge 1 ]]; then
    echo "PASS — observed: queen seeded; 1 breeder live (the floor is satisfiable)."
  else
    echo "FAIL — observed: queen seed did not produce a live breeder." >&2
  fi
else
  echo "FAIL — observed: queen spawn was denied." >&2
fi

# Module-level state shared across G1/G2/G3.
MAX_LIVE=1            # peak live population observed across all hot ticks
HOT_BUD_DECISIONS=0   # how many hot ticks the loop DECIDED to bud
G1_DONE_HOT=0         # set when the hot phase actually ran (gates the calm phase)

# ===========================================================================
# G1 — BUD ON HOT. Hold the partyline hot (consciousness 5); run a few
#      autonomic ticks; assert the swarm BUDDED in response (the loop both
#      DECIDES to bud and the live population rises above the seed). Budded
#      scouts carry a short lease, so the live count oscillates as they self-vent
#      and re-bud while it stays hot; we track both the bud decisions and the
#      PEAK live population reached.
# ===========================================================================
banner "G1 — BUD ON HOT (loud collective => the swarm buds scouts)"

if [[ "${BROADCAST_PRESENT}" -ne 1 ]]; then
  echo "SKIP — broadcast driver not yet built"
  echo "  (\`monster-swarm broadcast\` is being added by a sibling agent; without a"
  echo "   live partyline the autonomic loop has no hot collective to read, so it"
  echo "   correctly HOLDS. The lead runs the full green pass once it lands.)"
  G1_LIVE_BEFORE="$(fleet_live)"
  MAX_LIVE="${G1_LIVE_BEFORE:-1}"
else
  G1_LIVE_BEFORE="$(fleet_live)"
  MAX_LIVE="${G1_LIVE_BEFORE:-1}"
  echo "live before: ${G1_LIVE_BEFORE:-?}"
  echo "holding the partyline HOT (broadcast --consciousness 5 --hz 5 --secs 8) ..."
  start_hot_broadcast 5 8
  # Give the broadcaster a beat to put signals on the wire before the first read.
  "${SWARM_BIN}" vibe --dwell-ms 300 >/dev/null 2>&1 || true

  echo "running autonomic ticks (auto --bud-at 4 --reap-below 0) while hot:"
  for t in 1 2 3 4 5 6; do
    echo "    tick ${t}:"
    tok="$(auto_tick --bud-at 4 --reap-below 0)"
    [[ "${tok}" == "bud" ]] && HOT_BUD_DECISIONS=$((HOT_BUD_DECISIONS + 1))
    cur="$(fleet_live)"
    [[ -n "${cur}" && "${cur}" -gt "${MAX_LIVE}" ]] && MAX_LIVE="${cur}"
  done
  G1_DONE_HOT=1
  echo "hot ticks that DECIDED to bud: ${HOT_BUD_DECISIONS}; peak live observed: ${MAX_LIVE}"
  # PASS if the loop budded (decided to bud at least once AND the population rose
  # above the seed at some point). Budded scouts self-vent on their short lease,
  # so the instantaneous count oscillates — the bud DECISION + the peak are the
  # authoritative signals that the swarm responded to a hot collective.
  if [[ "${HOT_BUD_DECISIONS}" -ge 1 && "${MAX_LIVE}" -gt "${G1_LIVE_BEFORE:-1}" ]]; then
    echo "PASS — observed: the swarm budded scouts on hot consciousness (peak ${MAX_LIVE} > seed ${G1_LIVE_BEFORE})."
  else
    echo "FAIL — observed: hot collective did not cause the loop to bud." >&2
  fi
fi

# ===========================================================================
# G2 — CEILING HOLDS. Keep it hot, keep ticking; assert the live population
#      NEVER exceeds DECAGON = 10 (the FRF manifold ceiling bounds the loop).
# ===========================================================================
banner "G2 — CEILING HOLDS (population never exceeds DECAGON = ${DECAGON})"

if [[ "${BROADCAST_PRESENT}" -ne 1 ]]; then
  echo "SKIP — broadcast driver not yet built (no live partyline to drive over the ceiling)."
  echo "  max live observed so far: ${MAX_LIVE} (well within DECAGON = ${DECAGON})."
else
  echo "still hot; ticking hard to PUSH the population toward the ceiling:"
  for t in 1 2 3 4 5 6 7 8; do
    auto_tick --bud-at 4 --reap-below 0 >/dev/null 2>&1 || true
    cur="$(fleet_live)"
    [[ -n "${cur}" && "${cur}" -gt "${MAX_LIVE}" ]] && MAX_LIVE="${cur}"
  done
  echo "max live observed across all hot ticks: ${MAX_LIVE}"
  if [[ -n "${MAX_LIVE}" && "${MAX_LIVE}" -le "${DECAGON}" ]]; then
    echo "PASS — observed: population never exceeded DECAGON = ${DECAGON} (FRF ceiling held)."
  else
    echo "FAIL — observed: population exceeded the DECAGON ceiling (${MAX_LIVE} > ${DECAGON})." >&2
  fi
fi

# ===========================================================================
# G3 — REAP ON CALM. Stop the hot broadcaster; let the partyline go quiet; run
#      autonomic ticks; assert the controller EXPLICITLY reaps idle scouts when
#      the collective falls calm. The autonomic BUD spawns /bin/sleep with no
#      duration (in production the bud node is a long-lived aeon-monitor), so
#      budded scouts exit at once; to exercise the explicit auto-reap path we
#      seed long-lived scouts the calm loop can act on, then prove it reaps them.
# ===========================================================================
banner "G3 — REAP ON CALM (quiet collective => idle scouts are vented)"

if [[ "${BROADCAST_PRESENT}" -ne 1 || "${G1_DONE_HOT}" -ne 1 ]]; then
  echo "SKIP — broadcast driver not yet built (no scouts were budded; nothing to vent)."
  G3_LIVE_AFTER="$(fleet_live)"
else
  stop_broadcast
  echo "stopped the hot broadcaster; partyline going quiet (consciousness -> 0)."
  # Drop a few explicit calm signals so the read is unambiguous, then settle.
  "${SWARM_BIN}" broadcast --consciousness 0 --id demo-driver --count 3 --hz 5 >/dev/null 2>&1 || true

  # Seed long-lived scouts (sleep 3600, lease 3600) so the calm loop has stable
  # idle scouts to reap. The autonomic bud spawns /bin/sleep with no duration,
  # so budded scouts die at once and never reach a calm tick; these persist, so
  # the EXPLICIT auto-reap path (calm + live > min-live -> reap oldest scout)
  # actually fires and lands an actor=auto Reap on the chain.
  echo "seeding 2 long-lived idle scouts for the calm loop to reap explicitly:"
  for s in 1 2; do
    "${SWARM_BIN}" spawn --ucan "${UCAN}" --node sleep --id "idle-scout-${s}" \
      --caste scout --caps net --lease 3600 --grant-ttl 3600 -- 3600 >/dev/null 2>&1 || true
  done
  G3_LIVE_BEFORE="$(fleet_live)"
  echo "live entering calm phase: ${G3_LIVE_BEFORE:-?} (queen + idle scouts; hot peak was ${MAX_LIVE})"
  echo "running autonomic ticks (auto --bud-at 4 --reap-below 0) while calm:"
  G3_MIN_LIVE="${G3_LIVE_BEFORE:-1}"
  G3_REAP_DECISIONS=0
  for t in 1 2 3 4 5; do
    echo "    tick ${t}:"
    tok="$(auto_tick --bud-at 4 --reap-below 0)"
    [[ "${tok}" == "reap" ]] && G3_REAP_DECISIONS=$((G3_REAP_DECISIONS + 1))
    cur="$(fleet_live)"
    [[ -n "${cur}" && "${cur}" -lt "${G3_MIN_LIVE}" ]] && G3_MIN_LIVE="${cur}"
  done
  G3_LIVE_AFTER="$(fleet_live)"
  echo "live after calm ticks : ${G3_LIVE_AFTER:-?} (min during calm: ${G3_MIN_LIVE}); explicit auto-reap decisions: ${G3_REAP_DECISIONS}"
  # PASS if the controller EXPLICITLY reaped on calm AND the population settled
  # below where the calm phase began -- the inverse of G1's growth, and proof
  # that the LOOP reaps (not merely that leases expire).
  if [[ "${G3_REAP_DECISIONS}" -ge 1 && -n "${G3_LIVE_AFTER}" && -n "${G3_LIVE_BEFORE}" && "${G3_LIVE_AFTER}" -lt "${G3_LIVE_BEFORE}" ]]; then
    echo "PASS — observed: the controller EXPLICITLY reaped idle scouts on a calm collective (${G3_REAP_DECISIONS} auto-reap(s); live ${G3_LIVE_AFTER} < ${G3_LIVE_BEFORE})."
  else
    echo "FAIL — observed: calm collective did not trigger an explicit autonomic reap (${G3_REAP_DECISIONS} reap decisions)." >&2
  fi
fi

# ===========================================================================
# G4 — FLOOR HOLDS. Keep ticking calm; assert the loop NEVER reaps below the
#      queen: at least one breeder always remains in `list`.
# ===========================================================================
banner "G4 — FLOOR HOLDS (never reaps below the queen; >= 1 breeder remains)"

echo "ticking calm hard to try to vent EVERYTHING (the floor must stop it):"
FLOOR_OK=1
for t in 1 2 3 4 5 6; do
  auto_tick --bud-at 4 --reap-below 0 >/dev/null 2>&1 || true
  b="$(fleet_breeders)"
  l="$(fleet_live)"
  # The floor invariant: at least one breeder, and at least min-live, always.
  if [[ -z "${b}" || "${b}" -lt 1 || -z "${l}" || "${l}" -lt "${MIN_LIVE}" ]]; then
    FLOOR_OK=0
    echo "    tick ${t}: live=${l:-?} breeders=${b:-?}  <-- floor breached!"
    break
  fi
done
FINAL_BREEDERS="$(fleet_breeders)"
FINAL_LIVE="$(fleet_live)"
echo "after calm ticks: live=${FINAL_LIVE:-?} breeders=${FINAL_BREEDERS:-?}"
if [[ "${FLOOR_OK}" -eq 1 && "${FINAL_BREEDERS:-0}" -ge 1 && "${FINAL_LIVE:-0}" -ge "${MIN_LIVE}" ]]; then
  echo "PASS — observed: the loop never reaped below the queen (>= 1 breeder, >= ${MIN_LIVE} live)."
else
  echo "FAIL — observed: the floor was breached (a queen or the min-live floor was reaped)." >&2
fi

# ===========================================================================
# G5 — AUDITED + STABLE. The autonomic moves are on the tamper-evident record
#      (actor "auto" Spawn/Reap entries), the chain verifies (ok=true), and the
#      God-Formula stability weight stayed positive (>= 1) the whole way.
#
#      Guarded: SKIPs cleanly if the audit-actor "auto" tagging or the audit CLI
#      is not in the binary yet (sibling-pending). Stability weight is checked
#      unconditionally (vibe is present).
# ===========================================================================
banner "G5 — AUDITED + STABLE (auto moves on the record; chain verifies; stable)"

# Probe whether the audit subcommand exists at all (capture-then-grep; no SIGPIPE).
audit_probe="$("${SWARM_BIN}" audit --verify --json 2>&1 || true)"
AUDIT_PRESENT=0
if ! printf '%s' "${audit_probe}" | grep -qi 'unknown subcommand'; then
  AUDIT_PRESENT=1
fi

# --- G5.a stability weight stayed positive (>= 1) the whole demo.
echo "--- G5.a God-Formula stability weight in the fleet frame -> expect >= 1"
STAB="$(fleet_stability)"
echo "    vibe --json -> fleet.stabilityWeight = ${STAB:-?}"
if [[ -n "${STAB}" && "${STAB}" -ge 1 ]]; then
  echo "PASS — observed: stability weight >= 1 (the fleet frame stayed stable)."
else
  echo "FAIL — observed: stability weight is not >= 1." >&2
fi

# --- G5.b the autonomic moves are audited (actor "auto" Spawn/Reap) AND verify.
echo
echo "--- G5.b autonomic (actor=\"auto\") Spawn/Reap entries audited AND chain verifies"
if [[ "${AUDIT_PRESENT}" -ne 1 ]]; then
  echo "SKIP — audit CLI not yet built"
  echo "  (\`monster-swarm audit\` is being added by a sibling agent; the lead will run"
  echo "   the full green pass once it lands.)"
elif [[ "${BROADCAST_PRESENT}" -ne 1 ]]; then
  # Audit CLI present but no broadcaster => the loop only ever HELD, so there are
  # no autonomic Spawn/Reap entries to count. Still verify the chain so the
  # structural half of G5 is authoritative.
  echo "SKIP (auto entries) — broadcast driver absent, so the loop only HELD;"
  echo "  there are no autonomic Spawn/Reap entries yet. Verifying the live chain anyway:"
  verify_json="$("${SWARM_BIN}" audit --verify --json 2>/dev/null || true)"
  echo "    ${verify_json}"
  if printf '%s' "${verify_json}" | grep -q '"ok"[[:space:]]*:[[:space:]]*true'; then
    echo "PASS (chain) — observed: ok=true (the live audit chain recomputes and verifies)."
  else
    echo "FAIL (chain) — observed: the live chain did not verify; expected ok=true." >&2
  fi
else
  # The loop tags its own actions actor "auto:<did>". Autonomic buds are explicit
  # Spawn events on the chain; calm venting happens via lease expiry, which may
  # not emit an explicit auto Reap in this binary build — so the authoritative
  # signal is that autonomic moves (the auto buds) are on the record AND the
  # chain still verifies. We surface both counts.
  AUTO_SPAWNS="$(auto_action_count spawn)"
  AUTO_REAPS="$(auto_action_count reap)"
  echo "    autonomic Spawn entries (actor=auto:*): ${AUTO_SPAWNS:-0}"
  if [[ "${AUTO_REAPS:-0}" -gt 0 ]]; then
    echo "    autonomic Reap  entries (actor=auto:*): ${AUTO_REAPS} (the controller reaped idle scouts on calm)"
  else
    echo "    autonomic Reap  entries (actor=auto:*): 0 (no idle scouts survived to a calm tick this run)"
  fi
  verify_json="$("${SWARM_BIN}" audit --verify --json 2>/dev/null || true)"
  echo "    audit --verify -> ${verify_json}"
  AUTO_TOTAL=$(( ${AUTO_SPAWNS:-0} + ${AUTO_REAPS:-0} ))
  if [[ "${AUTO_TOTAL}" -gt 0 ]] \
     && printf '%s' "${verify_json}" | grep -q '"ok"[[:space:]]*:[[:space:]]*true'; then
    echo "PASS — observed: autonomic moves are on the chain (count=${AUTO_TOTAL}) AND ok=true (the swarm acting on its own is on the record)."
  else
    echo "FAIL — observed: missing autonomic entries or the chain did not verify." >&2
  fi
fi

# ===========================================================================
# Final banner.
